styleTag:
html, body {
  width: 100%;
  height: 100%;
  margin: 0;
  padding: 0;
  overflow: hidden;
  background: transparent;
}
iframe {
  width: 100%;
  height: 100%;
  border: none;
}

scriptTag:
var iframe = document.getElementById("pinball-frame");

// Forward all parent postMessages down to the nested game iframe
window.addEventListener("message", function(event) {
  if (iframe && iframe.contentWindow) {
    iframe.contentWindow.postMessage(event.data, "*");
  }
});

// Explicit callback for Pogly live variables
function onLiveVariableUpdate(name, value) {
  if (iframe && iframe.contentWindow) {
    iframe.contentWindow.postMessage({
      type: "variableUpdate",
      name: name,
      value: value
    }, "*");
  }
}

// Explicit callback for Pogly Twitch Chat integration
function onTwitchMessage(data) {
  if (iframe && iframe.contentWindow) {
    iframe.contentWindow.postMessage({
      type: "twitchMessage",
      data: data
    }, "*");
  }
}
